import anthropic, json

client = anthropic.Anthropic()

def build_content_licence_registry_entry(
    content_name: str,
    content_source_url: str,
    licence_type: str,
    licence_version: str,
    permitted_uses: list[str],
    prohibited_uses: list[str],
    attribution_required: bool,
    commercial_use_permitted: bool,
    training_use_explicit: str,   # "permitted", "prohibited", "silent"
    review_date: str,
    reviewed_by: str,
) -> dict:
    """
    Create a structured registry entry for a content source's licence.
    Builds a searchable record of what you can and cannot do with each source.
    """
    prompt = f"""
You are an IP compliance officer creating a registry entry for a content licence.

Content: {content_name}
Source: {content_source_url}
Licence: {licence_type} {licence_version}
Permitted uses: {permitted_uses}
Prohibited uses: {prohibited_uses}
Attribution required: {attribution_required}
Commercial use: {commercial_use_permitted}
Training use (explicit): {training_use_explicit}
Review date: {review_date}
Reviewed by: {reviewed_by}

Generate a concise registry entry that:
1. Summarises what the enterprise can and cannot do
2. Flags any ambiguities that need legal clarification
3. Sets a re-review trigger (e.g. "if licence version changes" or "in 12 months")
4. Recommends any contractual protections needed

Return ONLY JSON:
{{
  "content_name": "{content_name}",
  "licence_summary": "<string>",
  "permitted_ai_uses": ["<string>", ...],
  "prohibited_ai_uses": ["<string>", ...],
  "ambiguities": ["<string>", ...],
  "re_review_triggers": ["<string>", ...],
  "recommended_protections": ["<string>", ...],
  "overall_risk": "low" | "medium" | "high"
}}
""".strip()

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=600,
        messages=[{"role": "user", "content": prompt}]
    )
    return json.loads(response.content[0].text)
